# %% [code] Cell 22
import matplotlib.pyplot as plt
import seaborn as sns

plt.figure(figsize=(10, 6))
sns.scatterplot(x=X_test['temperature'], y=y_pred, alpha=0.6)
plt.title('Temperature vs. Predicted Load')
